function ProductCard({ product }) {
    return (
      <div style={styles.card}>
        <img src={product.image} alt={product.name} style={styles.image} />

        <h3>{product.name}</h3>
        <p>${product.price}</p>

        <button style={styles.button}>Add to Cart</button>
      </div>
    );
  }

  const styles = {
    card: {
      border: "1px solid #ddd",
      padding: "10px",
      borderRadius: "8px",
      width: "200px",
      textAlign: "center"
    },
    image: {
      width: "100%",
      height: "150px",
      objectFit: "cover"
    },
    button: {
      marginTop: "10px",
      padding: "8px",
      background: "#007bff",
      color: "white",
      border: "none",
      borderRadius: "5px"
    }
  };

  export default ProductCard;
